create table dirkspzm32.pps_arb_plan_ag_stl (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(6, 0) not null enable,
    arb_plan_pos_id         number(*, 0) not null enable,
    stueckliste_pos_id      number(*, 0) not null enable,
    prod_reihenfolge        number(*, 5),
    prod_menge_p_einheit    number(*, 3) default 1 not null enable,
    prod_menge_p_einheit_op varchar2(10 char) default 'MUL' not null enable,
    prod_menge_ix           number(*, 5) default 1 not null enable,
    created_date            date default sysdate not null enable,
    created_login_id        number(*, 0) default - 1 not null enable,
    last_change_date        date,
    last_change_login_id    number(*, 0),
    ag_alternative          number(*, 0) default 0 not null enable,
    arb_plan_id             number(*, 0) not null enable,
    sl_alternative          number(*, 0) default 0 not null enable,
    stueckliste_id          number(*, 0) not null enable
);

alter table dirkspzm32.pps_arb_plan_ag_stl
    add constraint pk_pps_arb_plan_ag_stl
        primary key ( arb_plan_pos_id,
                      ag_alternative,
                      stueckliste_pos_id,
                      firma_nr,
                      sid )
            using index enable;


